import { Kernel } from '@semantic-kernel/core';
import { VolatileMemoryStore } from '@semantic-kernel/memory-volatile-memory-store';

class MemoryIntegrityChecker {
  constructor(private kernel: Kernel) {}

  async validateRecall(collectionId: string, agentId: string): Promise<boolean> {
    const memoryStore = this.kernel.memory.getMemoryStore() as VolatileMemoryStore;
    const expectedPrefix = `agent_${agentId}_`;

    if (!collectionId.startsWith(expectedPrefix)) {
      console.error(`🚨 MEMORY HALLUCINATION: Invalid collection ${collectionId} for agent ${agentId}`);
      return false;
    }

    const records = await memoryStore.getBatchAsync(collectionId, []);
    return records.length > 0;
  }
}

// Usage
const checker = new MemoryIntegrityChecker(kernel);
const isValid = await checker.validateRecall('agent_finance_123', 'finance');
