from semantic_kernel.memory import SemanticTextMemory
from semantic_kernel.connectors.ai.open_ai import OpenAIChatCompletion

class AgentMemoryManager:
    def __init__(self, kernel):
        self.kernel = kernel
        self.memories = {}

    def get_agent_memory(self, agent_id: str):
        if agent_id not in self.memories:
            collection_name = f'{agent_id}_memory'
            self.memories[agent_id] = SemanticTextMemory(
                storage=self.kernel.memory_store,
                retriever=OpenAIChatCompletion(
                    deployment_name='gpt-4',
                    service_id='openai'
                )
            )
            self.memories[agent_id].register_collection(collection_name)
        return self.memories[agent_id], f'{agent_id}_memory'

# Usage
memory_mgr = AgentMemoryManager(kernel)
finance_memory, finance_collection = memory_mgr.get_agent_memory('finance')
